INSERT INTO video_shot_breakdown (video_id, total_frames_analyzed, face_frames, broll_frames, shot_counts, dominant_broll_type, secondary_broll_type, shot_sequence, analysis_confidence, notes) VALUES
('4fe54f02-783c-454a-a0fe-e763159c2f5e', 12, 0, 12, '{"FACE": 0, "PRODUCT_CLOSEUP": 4, "HANDS_ON_DEMO": 6, "LIFESTYLE": 1, "TEXT_SCREEN": 0, "TRANSITION": 0, "BEFORE_AFTER": 0, "PACKAGING": 1, "SCREEN_RECORDING": 0}'::jsonb, 'HANDS_ON_DEMO', 'PRODUCT_CLOSEUP', ARRAY['LIFESTYLE','PRODUCT_CLOSEUP','PRODUCT_CLOSEUP','HANDS_ON_DEMO','HANDS_ON_DEMO','HANDS_ON_DEMO','HANDS_ON_DEMO','PACKAGING','HANDS_ON_DEMO','HANDS_ON_DEMO','PRODUCT_CLOSEUP','PRODUCT_CLOSEUP'], 'high', 'Video is entirely B-roll demonstration with persistent overlay text. No talking head or face shots. Heavy focus on hands-on product demonstration in toilet bowl setting, establishing context and product benefit through visual evidence.'),
('90e2a52c-ce75-4937-a10f-2b8bd609211a', 8, 0, 8, '{"FACE": 0, "PRODUCT_CLOSEUP": 3, "HANDS_ON_DEMO": 2, "LIFESTYLE": 0, "TEXT_SCREEN": 0, "TRANSITION": 0, "BEFORE_AFTER": 0, "PACKAGING": 0, "SCREEN_RECORDING": 0}'::jsonb, 'PRODUCT_CLOSEUP', 'HANDS_ON_DEMO', ARRAY['PRODUCT_CLOSEUP','HANDS_ON_DEMO','PRODUCT_CLOSEUP','PRODUCT_CLOSEUP','HANDS_ON_DEMO','PRODUCT_CLOSEUP','PRODUCT_CLOSEUP','PRODUCT_CLOSEUP'], 'high', 'Fast-paced product showcase with vibrant neon cups in multiple color variations. Heavy emphasis on visual appeal and color variety. No face or traditional talking head present. Repetitive text overlay throughout all frames creates strong visual hook.'),
('97587968-314e-4517-800c-c41052087ea2', 13, 0, 13, '{"FACE": 0, "PRODUCT_CLOSEUP": 7, "HANDS_ON_DEMO": 4, "LIFESTYLE": 1, "TEXT_SCREEN": 0, "TRANSITION": 0, "BEFORE_AFTER": 1, "PACKAGING": 2, "SCREEN_RECORDING": 0}'::jsonb, 'PRODUCT_CLOSEUP', 'HANDS_ON_DEMO', ARRAY['BEFORE_AFTER','PRODUCT_CLOSEUP','PRODUCT_CLOSEUP','PACKAGING','HANDS_ON_DEMO','HANDS_ON_DEMO','PRODUCT_CLOSEUP','PRODUCT_CLOSEUP','HANDS_ON_DEMO','PRODUCT_CLOSEUP','LIFESTYLE','HANDS_ON_DEMO','PACKAGING'], 'high', 'Voiceover product comparison video with extensive product closeups and hands-on demonstrations. No talking head segments. Highly visual, feature-focused format typical of TikTok product review content.'),
('7986265d-330a-4359-a9c2-daeb4aeecdd4', 12, 12, 0, '{"FACE": 12, "PRODUCT_CLOSEUP": 0, "HANDS_ON_DEMO": 0, "LIFESTYLE": 0, "TEXT_SCREEN": 0, "TRANSITION": 0, "BEFORE_AFTER": 0, "PACKAGING": 0, "SCREEN_RECORDING": 0}'::jsonb, NULL, NULL, ARRAY['FACE','FACE','FACE','FACE','FACE','FACE','FACE','FACE','FACE','FACE','FACE','FACE'], 'high', 'Video consists entirely of talking head/demonstration shots with creator wearing the Natch Patch product throughout. No traditional B-roll or cutaways used. Product remains visible on creator''s midsection across all frames while he discusses features and benefits.'),
('83df0093-2d87-4387-bd21-9c4f4ac0fdc9', 12, 12, 0, '{"FACE": 12, "PRODUCT_CLOSEUP": 0, "HANDS_ON_DEMO": 0, "LIFESTYLE": 0, "TEXT_SCREEN": 0, "TRANSITION": 0, "BEFORE_AFTER": 0, "PACKAGING": 0, "SCREEN_RECORDING": 0}'::jsonb, NULL, NULL, ARRAY['FACE','FACE','FACE','FACE','FACE','FACE','FACE','FACE','FACE','FACE','FACE','FACE'], 'high', 'Video is almost entirely talking-head format with creator demonstrating the heating patch on his torso throughout. All frames show the same creator in bathroom setting with consistent lighting and composition. The patch remains visible on his abdomen throughout most frames, with minimal scene changes.'),
('70e0baf2-b95d-4e2c-8c1d-31130430308d', 12, 12, 0, '{"FACE": 8, "PRODUCT_CLOSEUP": 0, "HANDS_ON_DEMO": 4, "LIFESTYLE": 0, "TEXT_SCREEN": 0, "TRANSITION": 0, "BEFORE_AFTER": 0, "PACKAGING": 0, "SCREEN_RECORDING": 0}'::jsonb, 'HANDS_ON_DEMO', NULL, ARRAY['FACE','FACE','HANDS_ON_DEMO','HANDS_ON_DEMO','FACE','HANDS_ON_DEMO','HANDS_ON_DEMO','FACE','FACE','HANDS_ON_DEMO','HANDS_ON_DEMO','FACE'], 'high', 'Predominantly talking head format with integrated product demonstration shots showing hands applying products. Creator maintains direct camera engagement throughout while seamlessly transitioning between explanatory content and hands-on product application.');
