INSERT INTO video_visual_notes (video_id, format_type, hook_style, scene_descriptions, product_reveal_timestamp, overall_notes, cross_reference_notes) VALUES
('4fe54f02-783c-454a-a0fe-e763159c2f5e', 'product_demo', 'curiosity', '[{"timestamp": 0, "description": "Bathroom vanity with decorative items and plants. Hands reach toward product (toilet brush with cleaning caddy). Female hand holding brush."}, {"timestamp": 1, "description": "Close-up of toilet brush head revealing black bristles with white center in white/pink holder."}, {"timestamp": 2, "description": "Overhead view of toilet bowl. White brush with blue ring being inserted into water, creating foam action."}, {"timestamp": 3, "description": "Multiple shots of scrubbing toilet bowl with blue cleaning solution and dramatic foam visualization demonstrating cleaning power."}, {"timestamp": 4, "description": "Packaging reveal showing 5 blue refill cartridges in open box with white soap centers visible."}, {"timestamp": 5, "description": "Product lifestyle shot showing white/pink toilet brush holder on vanity among decor items."}, {"timestamp": 6, "description": "Close product shot of individual blue refill tablet being held in hand, demonstrating size and portability."}]'::jsonb, 5, 'Pure demonstration-driven visual strategy with no creator presence. The video uses persistent, lifestyle-contextual text overlay to create intrigue while focusing entirely on product efficacy visualization. Bold color contrast (blue cleaning liquid) and foam action shots emphasize cleaning power, while packaging and bulk refill reveal emphasizes value proposition and longevity.', 'Visuals directly match transcript: Opening hook text appears throughout (''every time a girl come to my crib''), demonstration of brush mechanism (lever/opening action), visible blue soap coloring in water, dramatic before/after toilet bowl transformation, refill cartridge multi-pack revelation showing quantity, and lifestyle bathroom context establishing aspirational home aesthetic.'),
('90e2a52c-ce75-4937-a10f-2b8bd609211a', 'product_demo', 'bold_claim', '[{"timestamp": 0, "description": "Single blue neon Red Bull cup with glowing ice, establishing product identity and visual aesthetic"}, {"timestamp": 1, "description": "Hand holding pink and blue Red Bull cups side-by-side, revealing color variety of product line"}, {"timestamp": 2, "description": "Wide shot of multiple glowing cups (cyan, pink, green, blue) with party hats in background, emphasizing collection and festive context"}, {"timestamp": 3, "description": "Angled close-up of multiple neon cups arranged in row showing color progression and glow effect"}, {"timestamp": 4, "description": "Hands inserting straw into cyan glowing cup, demonstrating product use and interactive element"}, {"timestamp": 5, "description": "Three cups in focus (cyan, lime green, magenta) with visible condensation and glow, emphasizing beverage nature"}, {"timestamp": 6, "description": "Multiple cups with varied angles and lighting showing depth and full product range (6+ colors visible)"}, {"timestamp": 7, "description": "Final wide collection shot showing full range of neon cups with blender and party decorations in background, complete lifestyle context"}]'::jsonb, 0, 'High-energy visual montage showcasing Red Bull''s neon glowing cups across multiple vibrant colors (blue, pink, cyan, lime green, magenta). The video leverages visual spectacle and bright, eye-catching aesthetics to create party/celebration atmosphere. Strong emphasis on product variation and collectibility drives engagement.', 'The repetitive ''Let the crazy party begin'' text aligns perfectly with the festive visual presentation and energetic product styling. The party-themed audio and text complement the bright neon colors and party decorations visible throughout. The discrepancy between the explicit/suggestive transcript lyrics and family-friendly visual presentation suggests possible audio-visual mismatch or repurposing of trending audio.'),
('97587968-314e-4517-800c-c41052087ea2', 'voiceover_broll', 'question', '[{"timestamp": 0, "description": "Side-by-side comparison shot of Dyson V8 (purple) and Shark Power Pro Flex (white) vacuums with text overlay ''Dyson vs Shark''. Both vacuums positioned on hardwood floor with piles of dirt/debris visible beneath each head unit demonstrating cleaning capability."}, {"timestamp": 2, "description": "Extreme closeup of Shark brush roll mechanism showing self-cleaning technology with clear crystalline structures visible along the roller."}, {"timestamp": 3, "description": "Shark PowerPro Flex packaging displayed prominently showing product features, benefits, and key selling points (MULTIFLEX, Dirt-Reveal, FloorDetect)."}, {"timestamp": 4, "description": "Hands-on demonstration of Dyson vacuum head mechanism showing dual suction settings control with red button visible."}, {"timestamp": 5, "description": "Closeup of Shark vacuum trigger mechanism with blue power button/indicator being pressed by user''s finger, demonstrating max power activation."}, {"timestamp": 6, "description": "Shark Power Pro Flex with blue Dirt-Reveal light activated, showing illuminated dust collection on hardwood floor under furniture."}, {"timestamp": 7, "description": "Shark canister being removed from vacuum body, demonstrating large capacity and easy emptying mechanism."}, {"timestamp": 8, "description": "Dyson dust canister closeup showing capacity and dust collection features."}, {"timestamp": 9, "description": "User''s hand pressing Dyson control buttons, highlighting multiple power settings and features on the handheld unit."}, {"timestamp": 10, "description": "Shark Power Pro Flex folding mechanism demonstrated with vacuum bent/articulated to show storage convenience."}, {"timestamp": 11, "description": "Lifestyle shot of Shark vacuum being used under low furniture (sofa) demonstrating MULTIFLEX articulation advantage versus competitor."}, {"timestamp": 12, "description": "Shark Power Pro Flex full-length product shot being held vertically, showing compact form factor and design aesthetics."}, {"timestamp": 13, "description": "Shark Power Pro Flex packaging box showing brand identity, product name ''POWERPRO FLEX REVEAL'', key features, and product positioning in retail environment."}]'::jsonb, 0, 'Pure voiceover product comparison using dynamic closeups, side-by-side demonstrations, and hands-on feature reveals. Visual strategy emphasizes mechanical details, performance testing, and product differentiation through action shots. No creator appearance; focus entirely on product specs and capabilities shown through high-quality macro and lifestyle cinematography.', 'Visuals directly support transcript claims: brush roll closeups correspond to ''self-cleaning'' discussion, Dirt-Reveal light demo matches ''blue reveal light'' mention, canister size shots support ''large capacity'' advantage, furniture navigation scenes prove MULTIFLEX flexibility claim, control mechanism demos illustrate suction settings comparison, and folding mechanism supports storage convenience discussion.'),
('7986265d-330a-4359-a9c2-daeb4aeecdd4', 'talking_head', 'shock_value', '[{"timestamp": 0, "description": "Creator holds up sealed Natch Patch product with visible green packaging and Japanese characters. Makes shocked expression with text overlay ''I did NOT expect the $natch....\ud83d\ude2d'' introducing the product."}, {"timestamp": 3, "description": "Creator peels back layers of patch, demonstrating application process on his midsection with instructional narration about peeling steps."}, {"timestamp": 6, "description": "Creator applies patch to stomach area, expressing immediate reaction (''whoo, I already feel it'') while maintaining focus on product placement and visibility."}, {"timestamp": 9, "description": "Creator discusses product benefits and ingredients while holding up packaging with visible branding and holding phone showing reviews/ingredients information."}, {"timestamp": 12, "description": "Creator displays full five-pack box of product with green and white packaging, discussing pack quantity and results, emphasizing scarcity and stock status."}]'::jsonb, 0, 'The video uses an entirely talking-head format where the creator is both the demonstrator and the focus throughout. The Natch Patch product remains prominently displayed on his midsection for 80% of the video, creating consistent product visibility. The strategy relies on authentic reaction-based content with shock-value hook and credibility-building through review mentions and ingredient transparency.', 'Visual pacing matches transcript flow: opening shock reaction, step-by-step application narration, immediate benefit claim (''already feel it''), Japanese manufacturing credibility angle, ingredient discussion with packaging visibility, pack quantity reveal, and closing sales urgency with CTA and scarcity messaging.'),
('83df0093-2d87-4387-bd21-9c4f4ac0fdc9', 'talking_head', 'shock_value', '[{"timestamp": 0, "description": "Creator shirtless, smiling widely with patch applied to abdomen. Text overlay introduces the product as Japanese ''natch patches'' with emphasis on intensity."}, {"timestamp": 3, "description": "Close-up of creator''s face showing surprised/concerned expression. Visible thermometer or temperature indicator behind him suggesting heat measurement."}, {"timestamp": 6, "description": "Creator demonstrating peeling/application process of the patch, holding edges and showing the multi-layer removal process with facial reactions."}, {"timestamp": 9, "description": "Creator shirtless showing fully applied green patch on torso, narrating experience and emphasizing the ''heating up'' sensation with hand gestures."}, {"timestamp": 12, "description": "Creator holding product packaging (HIKKA brand visible), discussing bulk purchasing strategy (5-pack, ordered 3) and directing viewers to link in bio with urgency around stock depletion."}]'::jsonb, 1, 'The video uses a consistent talking-head format to maintain viewer attention on the creator''s authentic reactions to the heating sensation. The strategic placement of the green patch on the torso serves as visual proof of product application throughout. Text overlays at beginning and middle create narrative hooks and manage expectations about intensity, while the final frames pivot to sales-focused CTAs emphasizing scarcity and urgency.', 'Visual elements directly support transcript: creator''s shocked expressions match ''hot as shit'' language, patch visibility demonstrates application steps mentioned (''peel this side, grab the herbal remedy, apply''), and packaging shots validate claims about five-pack availability and bulk ordering recommendations. Scarcity messaging in verbal CTA is reinforced by mentioning product is ''selling out like crazy.'''),
('70e0baf2-b95d-4e2c-8c1d-31130430308d', 'talking_head', 'shock_value', '[{"timestamp": 0, "description": "Creator with bandaged face (post-procedure aesthetic) making direct eye contact with wide expression, establishing hook about facelift at age 35. White headband and nose patch create visual interest and relatable post-treatment appearance."}, {"timestamp": 30, "description": "Creator removes bandages and demonstrates bare-faced skin with minimal makeup, establishing before state. Multiple angles showing clarity of complexion. Transition to product lineup reveal with four Korean skincare bottles displayed on table."}, {"timestamp": 60, "description": "Educational overlay showing spicule mechanism (cross-section diagram of skin penetration) with four benefit icons explaining collagen stimulation. Creator continues talking while holding pink serum product, demonstrating application on hand/arm with visible texture and consistency."}, {"timestamp": 90, "description": "Before/after comparison graphic showing close-up of skin (left side showing previous texture/concerns, right side showing improved appearance). Creator provides detailed testimonial about pore reduction and makeup application improvement."}, {"timestamp": 120, "description": "Creator holding various product containers, discussing pigmentation corrector benefits. Continues product-by-product breakdown with hands-on demonstrations of textures and application methods. Maintains engaged facial expressions and direct eye contact throughout."}]'::jsonb, 45, 'The video employs a high-engagement talking-head format anchored by the creator''s authentic reaction and emotional connection to the products. Visual strategy emphasizes relatability through the post-procedure bandage aesthetic (establishing credibility), transitions to bare-faced transparency (building trust), and integrates educational overlays with hands-on product demonstrations (combining education with persuasion). The persistent presence of the creator''s face and consistent eye contact maintains viewer engagement while product displays remain secondary visual elements.', 'Visual elements directly support transcript narrative arc: opening bandage setup validates the ''facelift'' hook, bare-faced reveal aligns with ''6 months of use'' claim and ''decade younger'' assertion, product lineup visualization corresponds to ''five products'' system explanation, spicule diagram supports ''micro-needling in bottle'' terminology, before/after graphic reinforces visible results claims about pore reduction and texture smoothing, and final product handling demonstrates accessibility and ease of use supporting value proposition against $3,000 professional treatment cost.');
INSERT INTO video_visual_scripts (video_id, full_visual_script, is_primary_script) VALUES
('4fe54f02-783c-454a-a0fe-e763159c2f5e', 'The video opens with a bathroom vanity scene featuring plants and decorative items, establishing a lifestyle context. A female hand reaches toward and picks up a white toilet brush with a blue ring accent from a pink caddy holder, immediately revealing the product. Close-up shots showcase the brush head''s black bristles with a white center, then transition to overhead toilet bowl shots where the brush is inserted into water, creating vivid blue cleaning solution and impressive foam action. Multiple subsequent shots show vigorous scrubbing motions with expanding blue water and bubbles, visually demonstrating the product''s cleaning efficacy and the integrated soap system. The video then shifts to a packaging reveal showing five blue refill cartridges in an opened box, emphasizing the "come with mad of them" value proposition from the transcript. A final product lifestyle shot displays the brush holder on a clean vanity, followed by a close-up of a single refill tablet held in hand. Throughout, persistent white text overlay reading "EVERYTIME A GIRL COME TO MY CRIB AND SEE THIS..." maintains narrative continuity and curiosity.', true),
('90e2a52c-ce75-4937-a10f-2b8bd609211a', 'The video opens with a single blue neon-glowing Red Bull cup held prominently, immediately establishing the product''s distinctive visual aesthetic. The second frame reveals a hand displaying two cups (pink and blue) side-by-side, introducing the color variety. The third and subsequent frames expand to showcase an increasingly elaborate collection of glowing cups in cyan, lime green, magenta, and blue, arranged artfully with party decorations including hats and a blender visible in the background. Mid-video transitions feature close-up angles emphasizing the condensation and luminescent qualities of the cups, with one frame showing a straw being inserted into a cup to demonstrate functionality. The final frames present an expansive wide shot displaying the complete range of neon cups (6+ colors) arranged in formation with festive party props, creating a celebratory context that reinforces the ''crazy party'' messaging. Throughout all frames, the persistent text overlay ''Let the crazy party begin😎'' maintains brand messaging consistency.', true),
('97587968-314e-4517-800c-c41052087ea2', 'The video opens with a striking side-by-side comparison of the Dyson V8 and Shark Power Pro Flex vacuums positioned on hardwood flooring, with piles of debris beneath each unit demonstrating their cleaning performance. The creator then transitions through a series of extreme closeup shots of the brush roll mechanisms, canister systems, and control interfaces, with hands-on demonstrations showing key features like the Shark''s trigger-activated max power, its illuminated Dirt-Reveal light that highlights dust and pet hair, and the large transparent canister. Extreme detail shots showcase the Dyson''s dual suction button controls, while lifestyle footage demonstrates the Shark''s MULTIFLEX articulation allowing it to reach under low furniture—a key differentiator mentioned in the voiceover. The video culminates with full product shots and packaging displays of both vacuums, emphasizing storage and design benefits. Throughout, the visual strategy relies entirely on product demonstration rather than talking-head presentation, creating an immersive, feature-focused comparison experience.', true),
('7986265d-330a-4359-a9c2-daeb4aeecdd4', 'The video opens with the creator displaying an unopened Natch Patch product in its sealed packaging, expressing shock at the results with an emoji-overlaid caption. He then demonstrates the three-step application process—peeling back successive layers while narrating each step—before applying the green herbal patch directly to his midsection. Throughout the demonstration, the creator maintains animated facial expressions and hand gestures to convey genuine surprise at how the product feels and works. The middle section features the creator discussing product benefits and ingredients while either pointing to the patch on his body or holding up packaging to showcase branding and details. The final frames show him displaying the five-pack box and white/green product packaging while delivering closing sales messaging about reviews, ingredient quality, and stock availability, creating urgency through scarcity language.', true),
('83df0093-2d87-4387-bd21-9c4f4ac0fdc9', 'The video opens with a shirtless creator displaying a bright green heating patch applied to his abdomen, immediately establishing the product and grabbing attention with an enthusiastic expression. His face dominates the frame throughout all twelve clips, with consistent bathroom lighting and white tile background. The creator progresses through various facial expressions—from initial enjoyment to shock to enthusiasm—as he verbally describes the application process and sensations. Key moments include him demonstrating the multi-layer peeling process, expressing surprise at the heat intensity, and displaying the full product packaging near the conclusion. The patch remains prominently visible throughout most frames, serving as continuous visual confirmation of the product being reviewed. The final frames shift focus to the packaging and product branding as the creator delivers purchase instructions and scarcity warnings.', true),
('70e0baf2-b95d-4e2c-8c1d-31130430308d', 'The video opens with a dramatic hook—the creator facing the camera with a white headband and nose patch, evoking post-surgical recovery, immediately establishing the controversial claim. She removes the bandages to reveal her bare face, no makeup, presenting authenticity and transparency about her starting point. The scene transitions to a full product lineup reveal, four bottles of Korean skincare arranged on a table, introducing the system visually. An educational overlay displays cross-sectional diagrams of how spicules work on skin layers, with benefit icons explaining collagen stimulation. Throughout, the creator demonstrates product textures and application methods with close-ups of her hands applying serums and creams. A before/after comparison graphic appears, showing detailed skin texture changes. The creator maintains direct eye contact and animated facial expressions throughout, alternating between talking-head segments and hands-on product demonstrations, creating an intimate, trustworthy testimonial format that makes professional skincare feel accessible and relatable.', true);